using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public sealed class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public sealed class EvaluationMetricsResponse
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public IReadOnlyList<ClassMetric> PerClassMetrics { get; set; } = [];
}

public sealed class ClassMetric
{
    public string ClassName { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _classLabels;
    private readonly EvaluationMetricsResponse _metrics;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.3);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract class labels from the trained model's key-value mapping
        var labelColumn = split.TrainSet.Schema["Label"];
        var keyType = labelColumn.Type as KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        labelColumn.GetKeyValues(ref keyValues);
        _classLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        _metrics = Evaluate(split.TestSet);
    }

    private EvaluationMetricsResponse Evaluate(IDataView testData)
    {
        var predictions = _model.Transform(testData);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var perClass = new List<ClassMetric>();
        for (var i = 0; i < metrics.PerClassLogLoss.Count && i < _classLabels.Length; i++)
        {
            perClass.Add(new ClassMetric
            {
                ClassName = _classLabels[i],
                Precision = metrics.ConfusionMatrix.PerClassPrecision[i],
                Recall = metrics.ConfusionMatrix.PerClassRecall[i]
            });
        }

        return new EvaluationMetricsResponse
        {
            MacroAccuracy = (float)metrics.MacroAccuracy,
            MicroAccuracy = (float)metrics.MicroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = perClass
        };
    }

    public EvaluationMetricsResponse GetMetrics() => _metrics;

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_classLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        return Ok(classifier.Predict(request));
    }

    [HttpGet("metrics")]
